--// ZT HUB v3 - Cargador Ofuscado (Base64)
--// Sube ESTE archivo a GitHub. El código real está oculto aquí.

local http = game:GetService("HttpService")
local encoded = [[]]

local success, decoded = pcall(function()
    return http:Base64Decode(encoded)
end)

if success and decoded then
    local func, err = loadstring(decoded)
    if func then
        func()
    else
        warn("[ZT HUB] Error al compilar: " .. tostring(err))
    end
else
    warn("[ZT HUB] Error al decodificar Base64")
end
